import { GoogleGenAI, Type } from "@google/genai";
import { SlideContent, SlideStyle } from '../types';
import { STYLES } from '../constants';

// Initialize the client
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const generateOutline = async (
  text: string,
  count: number,
  style: SlideStyle
): Promise<Omit<SlideContent, 'isGenerating'>[]> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);

  const prompt = `
    You are an expert presentation designer.
    Analyze the following text and split it into exactly ${count} slides.
    For each slide, extract a Title, 3-5 concise Bullet Points, and write a detailed "Visual Description" for an AI image generator to create the slide visuals.

    The target style is: ${styleDef?.name} (${styleDef?.description}).

    Source Text:
    ${text.substring(0, 15000)} 
  `;

  // Schema for structured JSON output
  const schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING },
        bulletPoints: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING } 
        },
        visualPrompt: { type: Type.STRING, description: "A detailed description of how the slide should look, including layout and imagery, suitable for an image generation model." }
      },
      required: ["title", "bulletPoints", "visualPrompt"]
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: schema,
        systemInstruction: "You are a helpful assistant that structures content for presentations."
      }
    });

    const rawData = JSON.parse(response.text || '[]');

    // Map to our app's internal structure
    return rawData.map((item: any, index: number) => ({
      id: `slide-${Date.now()}-${index}`,
      pageNumber: index + 1,
      title: item.title,
      bulletPoints: item.bulletPoints,
      visualPrompt: item.visualPrompt,
    }));

  } catch (error) {
    console.error("Error generating outline:", error);
    throw error;
  }
};

export const generateSlideImage = async (
  slide: SlideContent,
  style: SlideStyle
): Promise<string> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);

  // Construct a prompt that asks the model to render the text onto the image
  // Gemini 3 Pro Image (Nano Banana Pro) has strong text rendering capabilities.
  const prompt = `
    ${styleDef?.promptModifier}

    Specific Content for this slide:
    TITLE: "${slide.title}"

    BULLET POINTS (Must be legible and clearly formatted as a list):
    ${slide.bulletPoints.map(bp => `- ${bp}`).join('\n')}

    VISUAL CONTEXT:
    ${slide.visualPrompt}

    REQUIREMENTS:
    1. The image MUST be a complete 16:9 presentation slide.
    2. The Title and Bullet Points MUST be visible and readable text on the image.
    3. Ensure high contrast between text and background.
    4. Do not include any UI elements (like browser bars), just the slide design.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Nano Banana Pro equivalent
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
          imageSize: "2K" // High quality for PPT
        }
      }
    });

    // Extract image
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data returned");

  } catch (error) {
    console.error(`Error generating image for slide ${slide.pageNumber}:`, error);
    throw error;
  }
};

