import React, { useRef } from 'react';
import { SlideContent } from '../types';
import { RefreshCw, Download, Image as ImageIcon, Check } from 'lucide-react';
// We are using ES modules, assume jspdf is available in the environment via default import or window
import { jsPDF } from 'jspdf'; 

interface Props {
  slides: SlideContent[];
  onRegenerate: (slideId: string) => void;
}

const StepGeneration: React.FC<Props> = ({ slides, onRegenerate }) => {
  const isAllDone = slides.every(s => !s.isGenerating && s.generatedImageUrl);

  const handleDownloadPDF = () => {
    const doc = new jsPDF({
      orientation: 'landscape',
      unit: 'px',
      format: [1920, 1080] // Standard 16:9 HD resolution
    });

    slides.forEach((slide, index) => {
      if (index > 0) doc.addPage();
      if (slide.generatedImageUrl) {
        doc.addImage(slide.generatedImageUrl, 'PNG', 0, 0, 1920, 1080);
      }
    });

    doc.save('gemini-presentation.pdf');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20">
      <div className="flex justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200 sticky top-4 z-20">
        <div>
          <h2 className="text-xl font-bold text-slate-800">Final Slides</h2>
          <p className="text-sm text-slate-500">
            {isAllDone ? "All slides ready. Review and download." : "Generating high-fidelity slides..."}
          </p>
        </div>
        <button
          onClick={handleDownloadPDF}
          disabled={!isAllDone}
          className={`px-6 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors ${
            isAllDone 
              ? 'bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-600/20' 
              : 'bg-slate-200 text-slate-400 cursor-not-allowed'
          }`}
        >
          <Download className="w-4 h-4" />
          Download PDF
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {slides.map((slide) => (
          <div key={slide.id} className="group relative bg-slate-900 rounded-xl overflow-hidden aspect-video shadow-lg">

            {/* Image Layer */}
            {slide.generatedImageUrl ? (
              <img 
                src={slide.generatedImageUrl} 
                alt={slide.title} 
                className="w-full h-full object-cover"
              />
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 space-y-4">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white"></div>
                <p className="text-sm font-medium animate-pulse">Designing Slide {slide.pageNumber}...</p>
              </div>
            )}

            {/* Overlay Actions */}
            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
               {slide.generatedImageUrl && !slide.isGenerating && (
                 <>
                   <button 
                    onClick={() => onRegenerate(slide.id)}
                    className="bg-white/10 hover:bg-white/20 text-white backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium transition-colors"
                   >
                     <RefreshCw className="w-4 h-4" />
                     Regenerate
                   </button>
                   <a 
                    href={slide.generatedImageUrl} 
                    download={`slide-${slide.pageNumber}.png`}
                    className="bg-white/10 hover:bg-white/20 text-white backdrop-blur-md px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium transition-colors"
                   >
                     <Download className="w-4 h-4" />
                     Save Image
                   </a>
                 </>
               )}
            </div>

            {/* Label */}
            <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md text-white text-xs px-2 py-1 rounded">
              Slide {slide.pageNumber}
            </div>

            {/* Generating State Overlay */}
            {slide.isGenerating && slide.generatedImageUrl && (
               <div className="absolute inset-0 bg-black/70 flex items-center justify-center">
                  <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-500"></div>
               </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default StepGeneration;

import React, { useState, useCallback } from 'react';
import StepInput from './components/StepInput';
import StepOutline from './components/StepOutline';
import StepGeneration from './components/StepGeneration';
import { AppStep, GenerationConfig, SlideContent } from './types';
import { generateOutline, generateSlideImage } from './services/geminiService';
import { Layers } from 'lucide-react';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.INPUT);
  const [config, setConfig] = useState<GenerationConfig | null>(null);
  const [slides, setSlides] = useState<SlideContent[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Step 1 -> 2: Generate Outline
  const handleConfigSubmit = async (newConfig: GenerationConfig) => {
    setConfig(newConfig);
    setIsLoading(true);
    try {
      const outline = await generateOutline(newConfig.sourceText, newConfig.slideCount, newConfig.style);
      setSlides(outline.map(s => ({ ...s, isGenerating: false })));
      setCurrentStep(AppStep.OUTLINE);
    } catch (error) {
      alert("Failed to generate outline. Please check your API key and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Generate Images
  const handleOutlineConfirm = async () => {
    if (!config) return;
    setCurrentStep(AppStep.GENERATION);

    // Trigger generation for all slides sequentially (or small batches) to avoid rate limits
    // For better UX, we'll start them but the UI updates independently
    generateAllSlides(slides, config);
  };

  const generateAllSlides = async (currentSlides: SlideContent[], cfg: GenerationConfig) => {
    // Clone array to update state
    let updatedSlides = [...currentSlides];

    // Helper to update a specific slide in state
    const updateSlideState = (id: string, updates: Partial<SlideContent>) => {
      setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
    };

    // Process sequentially to be safe with rate limits
    for (const slide of currentSlides) {
      updateSlideState(slide.id, { isGenerating: true });
      try {
        const imageUrl = await generateSlideImage(slide, cfg.style);
        updateSlideState(slide.id, { isGenerating: false, generatedImageUrl: imageUrl });
      } catch (e) {
        console.error("Failed to generate slide", slide.id);
        updateSlideState(slide.id, { isGenerating: false }); // Leave as failed/empty
      }
    }
  };

  const handleUpdateSlide = (id: string, updates: Partial<SlideContent>) => {
    setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const handleRegenerateSlide = async (id: string) => {
    if (!config) return;
    const slide = slides.find(s => s.id === id);
    if (!slide) return;

    handleUpdateSlide(id, { isGenerating: true });
    try {
      const imageUrl = await generateSlideImage(slide, config.style);
      handleUpdateSlide(id, { isGenerating: false, generatedImageUrl: imageUrl });
    } catch (e) {
      handleUpdateSlide(id, { isGenerating: false });
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-blue-600">
            <Layers className="w-6 h-6" />
            <span className="font-bold text-lg tracking-tight">Gemini PPT</span>
          </div>

          {/* Progress Stepper */}
          <div className="hidden md:flex items-center gap-4 text-sm font-medium">
             <div className={`px-3 py-1 rounded-full ${currentStep === AppStep.INPUT ? 'bg-blue-100 text-blue-700' : 'text-slate-400'}`}>1. Input</div>
             <div className="w-8 h-px bg-slate-200"></div>
             <div className={`px-3 py-1 rounded-full ${currentStep === AppStep.OUTLINE ? 'bg-blue-100 text-blue-700' : 'text-slate-400'}`}>2. Review</div>
             <div className="w-8 h-px bg-slate-200"></div>
             <div className={`px-3 py-1 rounded-full ${currentStep === AppStep.GENERATION ? 'bg-blue-100 text-blue-700' : 'text-slate-400'}`}>3. Create</div>
          </div>

          <div className="w-20"></div> {/* Spacer for balance */}
        </div>
      </header>

      {/* Main Content */}
      <main className="p-6">
        {currentStep === AppStep.INPUT && (
          <StepInput onNext={handleConfigSubmit} isLoading={isLoading} />
