  id: string;
  pageNumber: number;
  title: string;
  bulletPoints: string[];
  visualPrompt: string; // The instruction for the image model
  generatedImageUrl?: string;
  isGenerating: boolean;
  error?: string; // Add error field to track generation failures
}

