            <div className="mt-2 text-[10px] text-slate-400 text-right">
              支持直接读取 Word 和 PDF 格式
            </div>
          </div>
        </div>

        {/* Right Column: Settings */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-6">

            {/* Slide Count */}
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">
                生成页数: {slideCount} 页
              </label>
              <input
                type="range"
                min={MIN_SLIDES}
                max={MAX_SLIDES}
                value={slideCount}
                onChange={(e) => setSlideCount(parseInt(e.target.value))}
                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
              <div className="flex justify-between text-xs text-slate-400 mt-1">
                <span>{MIN_SLIDES}</span>
                <span>{MAX_SLIDES}</span>
              </div>
            </div>

            {/* Style Selection */}
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-3">
                视觉设计风格
              </label>
              <div className="grid grid-cols-1 gap-3">
                {STYLES.map((s) => (
                  <button
                    key={s.id}
                    onClick={() => setSelectedStyle(s.id)}
                    className={`flex items-center gap-3 p-3 rounded-lg border text-left transition-all ${
                      selectedStyle === s.id
                        ? 'border-blue-500 bg-blue-50 ring-1 ring-blue-500'
                        : 'border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    <div className={`w-8 h-8 rounded-full flex-shrink-0 ${s.previewColor}`} />
                    <div>
                      <div className="text-sm font-medium text-slate-900">{s.name}</div>
                      <div className="text-xs text-slate-500 line-clamp-1">{s.description}</div>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <button
              onClick={handleSubmit}
              disabled={!text.trim() || isLoading || isFileLoading}
              className={`w-full py-4 rounded-lg flex items-center justify-center gap-2 font-semibold text-white transition-all transform active:scale-95 ${
                !text.trim() || isLoading || isFileLoading
                  ? 'bg-slate-300 cursor-not-allowed'
                  : 'bg-blue-600 hover:bg-blue-700 shadow-lg shadow-blue-600/20'
              }`}
            >
              {isLoading ? (
                <>处理中...</>
              ) : (
                <>
                  <Wand2 className="w-5 h-5" />
                  生成 PPT 大纲
                </>
              )}
            </button>

          </div>
        </div>
      </div>
    </div>
  );
};

