import { GoogleGenAI, Type } from "@google/genai";
import { SlideContent, SlideStyle } from '../types';
import { STYLES } from '../constants';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found. Please select an API Key first.");
  return new GoogleGenAI({ apiKey });
};

/**
 * Generates a high-depth PPT outline using Gemini 3 Pro with Thinking enabled.
 * Implements recommended configuration for thinkingBudget + maxOutputTokens.
 */
export const generateOutline = async (
  text: string,
  count: number,
  style: SlideStyle
): Promise<Omit<SlideContent, 'isGenerating'>[]> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);

  // Truncate text to avoid token overflow while keeping high context (approx 30k chars)
  const truncatedText = text.length > 30000 ? text.substring(0, 30000) + "..." : text;

  const prompt = `
    你是一位顶尖的策略咨询顾问（如麦肯锡或波士顿咨询）。
    你的任务是基于提供的“原始素材”，制作一份深度、专业且全面的 PPT 大纲。

    **目标任务**：
    1. 将素材深度解构，并逻辑严密地分布到正好 ${count} 页幻灯片中。
    2. **拒绝表面化**：每一页必须保留素材中的核心事实、关键数据、逻辑细节和深度洞察。
    3. 每页幻灯片应包含 5-8 个内容充实的“要点”（Bullet Points），每个要点应是一句完整、具有信息含量的专业描述。
    4. 确保幻灯片之间有清晰的叙事流（如：背景分析 -> 核心痛点 -> 深度诊断 -> 战略方案 -> 落地执行）。

    **风格要求**：${styleDef?.name} (${styleDef?.description})。

    **技术规格**：
    - Title & Bullet Points: 必须使用与原文相同的语言（中文）。
    - Visual Description: 必须使用英文（English），描述高保真的、具有视觉冲击力的设计构图。

    原始素材内容：
    ${truncatedText}
  `;

  const schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING, description: "Slide Title" },
        bulletPoints: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING },
          description: "5-8 detailed bullet points reflecting depth of source material."
        },
        visualPrompt: { type: Type.STRING, description: "Visual direction for the image generator (English)." }
      },
      required: ["title", "bulletPoints", "visualPrompt"],
    }
  };

  const attemptGeneration = async (modelName: string, useThinking: boolean) => {
    const config: any = {
      responseMimeType: 'application/json',
      responseSchema: schema,
      systemInstruction: "你是一个专业的PPT架构师，擅长将复杂的长文档转化为逻辑严密、内容充实的专业幻灯片大纲。"
    };

    if (useThinking) {
      // Per documentation: must set maxOutputTokens and thinkingBudget together.
      // Total output tokens 8192, with 4096 reserved for thinking.
      // Leaving 4096 tokens for the actual JSON response.
      config.maxOutputTokens = 8192;
      config.thinkingConfig = { thinkingBudget: 4096 };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: [{ parts: [{ text: prompt }] }],
      config
    });

    if (!response.text) throw new Error(`Model ${modelName} returned empty text`);
    return JSON.parse(response.text.trim());
  };

  try {
    // Primary attempt: Gemini 3 Pro with Thinking for maximum quality
    console.log("Attempting primary generation with Gemini 3 Pro (Thinking)...");
    const rawData = await attemptGeneration('gemini-3-pro-preview', true);

    return rawData.map((item: any, index: number) => ({
      id: `slide-${Date.now()}-${index}`,
      pageNumber: index + 1,
      title: item.title || `第 ${index + 1} 页`,
      bulletPoints: item.bulletPoints || [],
      visualPrompt: item.visualPrompt || "Professional slide background",
    }));

  } catch (error: any) {
    console.warn("Primary generation failed, falling back to Gemini 3 Flash:", error);

    try {
      // Fallback: Gemini 3 Flash (Fast and more likely to succeed if Pro is hitting quota/limits)
      const rawData = await attemptGeneration('gemini-3-flash-preview', false);
      return rawData.map((item: any, index: number) => ({
        id: `slide-${Date.now()}-${index}`,
        pageNumber: index + 1,
        title: item.title || `第 ${index + 1} 页`,
        bulletPoints: item.bulletPoints || [],
        visualPrompt: item.visualPrompt || "Professional slide background",
      }));
    } catch (fallbackError: any) {
      console.error("Fallback also failed:", fallbackError);
      throw new Error(`无法生成大纲。原因：${error.message || "请求被拒绝"}`);
    }
  }
};

export const generateSlideImage = async (
  slide: SlideContent,
  style: SlideStyle
): Promise<string> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);

  // We use the "Nano Banana Pro" model for high-quality slide generation
  const prompt = `
    ${styleDef?.promptModifier}

    Slide Context:
    TITLE: "${slide.title}"
    CORE CONTENT:
    ${slide.bulletPoints.map(bp => `- ${bp}`).join('\n')}

    LAYOUT & VISUALS:
    ${slide.visualPrompt}

    MANDATORY DESIGN RULES:
    1. This is a FINAL PRESENTATION SLIDE.
    2. Typeset the title and all bullet points clearly. 
    3. Ensure high legibility and professional aesthetic.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
          imageSize: "1K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Image model failed to return binary data.");

  } catch (error: any) {
    console.error(`Slide ${slide.pageNumber} image error:`, error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import StepInput from './components/StepInput';
import StepOutline from './components/StepOutline';
import StepGeneration from './components/StepGeneration';
import { AppStep, GenerationConfig, SlideContent } from './types';
import { generateOutline, generateSlideImage } from './services/geminiService';
import { Layers, Key, ExternalLink, Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.API_KEY);
  const [config, setConfig] = useState<GenerationConfig | null>(null);
  const [slides, setSlides] = useState<SlideContent[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingKey, setIsCheckingKey] = useState(true);
  const [globalError, setGlobalError] = useState<string | null>(null);

  // Check for API Key on mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        const aistudio = (window as any).aistudio;
        if (aistudio) {
          const hasKey = await aistudio.hasSelectedApiKey();
          if (hasKey) {
            setCurrentStep(AppStep.INPUT);
          } else {
            setCurrentStep(AppStep.API_KEY);
          }
        } else {
          setCurrentStep(AppStep.INPUT);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
        setCurrentStep(AppStep.INPUT);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const aistudio = (window as any).aistudio;
    if (aistudio) {
      try {
        await aistudio.openSelectKey();
        setCurrentStep(AppStep.INPUT); // Assume success per race condition rules
      } catch (e) {
        console.error("Failed to select key:", e);
      }
    }
  };

  const handleConfigSubmit = async (newConfig: GenerationConfig) => {
    setGlobalError(null);
    setConfig(newConfig);
    setIsLoading(true);
    try {
      const outline = await generateOutline(newConfig.sourceText, newConfig.slideCount, newConfig.style);
      if (outline && outline.length > 0) {
        setSlides(outline.map(s => ({ ...s, isGenerating: false })));
        setCurrentStep(AppStep.OUTLINE);
      } else {
        throw new Error("生成大纲内容为空，请尝试更换素材或减少生成页数。");
      }
    } catch (error: any) {
      console.error(error);
      setGlobalError(error.message || "生成大纲时遇到未知错误");
    } finally {
      setIsLoading(false);
    }
  };

  const handleOutlineConfirm = async () => {
    if (!config) return;
    setCurrentStep(AppStep.GENERATION);
    generateAllSlides(slides, config);
  };

  const generateAllSlides = async (currentSlides: SlideContent[], cfg: GenerationConfig) => {
    const updateSlideState = (id: string, updates: Partial<SlideContent>) => {
      setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
    };

    for (const slide of currentSlides) {
      updateSlideState(slide.id, { isGenerating: true, error: undefined });
      try {
        const imageUrl = await generateSlideImage(slide, cfg.style);
        updateSlideState(slide.id, { isGenerating: false, generatedImageUrl: imageUrl });
      } catch (e: any) {
        console.error("Failed to generate slide", slide.id, e);
        updateSlideState(slide.id, { 
          isGenerating: false, 
          error: e.message?.includes("403") ? "API 权限不足，请确认 Key 是否支持 Pro 模型" : "生成幻灯片失败，请重试"
        });
      }
    }
  };

  const handleUpdateSlide = (id: string, updates: Partial<SlideContent>) => {
    setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const handleRegenerateSlide = async (id: string) => {
    if (!config) return;
    const slide = slides.find(s => s.id === id);
    if (!slide) return;

    handleUpdateSlide(id, { isGenerating: true, error: undefined });
    try {
      const imageUrl = await generateSlideImage(slide, config.style);
      handleUpdateSlide(id, { isGenerating: false, generatedImageUrl: imageUrl });
    } catch (e: any) {
      handleUpdateSlide(id, { isGenerating: false, error: "重试失败，请检查网络或 Key 权限" });
    }
  };

  if (isCheckingKey) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    );
  }

  if (currentStep === AppStep.API_KEY) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4 font-sans">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl border border-slate-100 p-8 text-center space-y-6">
          <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-2">
            <Key className="w-8 h-8" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-slate-800 mb-2">需要 API 授权</h1>
            <p className="text-slate-500 text-sm leading-relaxed">
              请选择一个关联了 Google Cloud 计费项目的 API 密钥。
              <br/>推荐使用 Gemini 3 系列以获得最佳效果。
            </p>
          </div>
          <button
            onClick={handleSelectKey}
            className="w-full py-3 px-4 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-lg shadow-lg shadow-blue-600/20 transition-all active:scale-95 flex items-center justify-center gap-2"
          >
            选择 API 密钥
          </button>
          <div className="pt-4 border-t border-slate-100">
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="text-xs text-blue-500 hover:text-blue-600 flex items-center justify-center gap-1">
              了解 API 计费详情 <ExternalLink className="w-3 h-3" />
            </a>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-blue-600">
            <Layers className="w-6 h-6" />
