import mammoth from 'mammoth';
import * as pdfjsLib from 'pdfjs-dist';

pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.mjs';

interface Props {
  onNext: (config: GenerationConfig) => void;
  isLoading: boolean;
}

const StepInput: React.FC<Props> = ({ onNext, isLoading }) => {
  const [text, setText] = useState('');
  const [slideCount, setSlideCount] = useState(5);
  const [selectedStyle, setSelectedStyle] = useState<SlideStyle>(SlideStyle.PROFESSIONAL);
  const [isFileLoading, setIsFileLoading] = useState(false);
  const [userImage, setUserImage] = useState<string | null>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsFileLoading(true);
    const fileName = file.name.toLowerCase();
    try {
      if (fileName.endsWith('.docx')) {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        setText(result.value);
      } else if (fileName.endsWith('.pdf')) {
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        let fullText = "";
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const textContent = await page.getTextContent();
          fullText += textContent.items.map((item: any) => item.str).join(' ') + "\n";
        }
        setText(fullText);
      } else {
        const reader = new FileReader();
        reader.onload = (event) => setText(event.target?.result as string);
        reader.readAsText(file);
      }
    } catch (err) {
      alert("无法读取文件。");
    } finally {
      setIsFileLoading(false);
      e.target.value = '';
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => setUserImage(event.target?.result as string);
    reader.readAsDataURL(file);
  };

  const handleSubmit = () => {
    if (!text.trim()) return;
    onNext({
      sourceText: text,
      slideCount,
      style: selectedStyle,
      userImage: userImage || undefined
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="text-center space-y-2">
        <h1 className="text-4xl font-bold text-slate-800 tracking-tight flex items-center justify-center gap-3">
          AI PPT 工作台
          <span className="text-xs bg-blue-100 text-blue-600 px-2 py-1 rounded-full font-medium">Portrait AI版</span>
        </h1>
        <p className="text-slate-500 text-lg">支持上传照片，将您本人应用在专业幻灯片中。</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-semibold flex items-center gap-2 text-slate-700">
                <FileText className="w-5 h-5" />
                文字素材
              </h2>
              <label className={`cursor-pointer text-sm font-medium flex items-center gap-1 text-blue-600 hover:text-blue-700`}>
                <Upload className="w-4 h-4" /> 上传素材
                <input type="file" accept=".txt,.md,.docx,.pdf" className="hidden" onChange={handleFileChange} />
              </label>
            </div>
            <textarea
              className="w-full h-64 p-4 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none bg-slate-50 text-slate-800 text-sm"
              placeholder="粘贴您的报告内容..."
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
             <h2 className="text-lg font-semibold flex items-center gap-2 text-slate-700 mb-4">
                <User className="w-5 h-5" />
                人像照片 (可选)
             </h2>
             <div className="flex items-center gap-6">
                <label className="flex-shrink-0 w-32 h-32 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-colors relative overflow-hidden group">
                  {userImage ? (
                    <>
                      <img src={userImage} className="w-full h-full object-cover" alt="User" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                        <Upload className="w-6 h-6 text-white" />
                      </div>
                    </>
                  ) : (
                    <div className="text-center p-2">
                      <Upload className="w-6 h-6 text-slate-400 mx-auto mb-1" />
                      <span className="text-[10px] text-slate-500">上传职业照</span>
                    </div>
                  )}
                  <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                </label>
                <div className="flex-1">
                  <p className="text-sm text-slate-600 mb-2">上传您的个人照片，AI 将根据幻灯片主题，将您的形象融合到 PPT 页面中（例如作为主讲人）。</p>
                  {userImage && (
                    <button onClick={() => setUserImage(null)} className="text-xs text-red-500 font-medium flex items-center gap-1">
                      <X className="w-3 h-3" /> 移除照片
                    </button>
                  )}
                </div>
             </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-6">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">生成页数: {slideCount} 页</label>
              <input type="range" min={MIN_SLIDES} max={MAX_SLIDES} value={slideCount} onChange={(e) => setSlideCount(parseInt(e.target.value))} className="w-full accent-blue-600" />
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-3">视觉风格</label>
              <div className="grid grid-cols-1 gap-3">
