import React, { useState, useEffect } from 'react';
import StepInput from './components/StepInput';
import StepOutline from './components/StepOutline';
import StepGeneration from './components/StepGeneration';
import { AppStep, GenerationConfig, SlideContent } from './types';
import { generateOutline, generateSlideImage } from './services/geminiService';
import { Layers, Key, ExternalLink, Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<AppStep>(AppStep.API_KEY);
  const [config, setConfig] = useState<GenerationConfig | null>(null);
  const [slides, setSlides] = useState<SlideContent[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingKey, setIsCheckingKey] = useState(true);
  const [globalError, setGlobalError] = useState<string | null>(null);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const aistudio = (window as any).aistudio;
        if (aistudio && await aistudio.hasSelectedApiKey()) {
          setCurrentStep(AppStep.INPUT);
        } else {
          setCurrentStep(AppStep.API_KEY);
        }
      } catch {
        setCurrentStep(AppStep.INPUT);
      } finally {
        setIsCheckingKey(false);
      }
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    const aistudio = (window as any).aistudio;
    if (aistudio) {
      await aistudio.openSelectKey();
      setCurrentStep(AppStep.INPUT);
    }
  };

  const handleConfigSubmit = async (newConfig: GenerationConfig) => {
    setGlobalError(null);
    setConfig(newConfig);
    setIsLoading(true);
    try {
      const outline = await generateOutline(newConfig.sourceText, newConfig.slideCount, newConfig.style);
      if (outline && outline.length > 0) {
        setSlides(outline.map(s => ({ ...s, isGenerating: false })));
        setCurrentStep(AppStep.OUTLINE);
      } else {
        throw new Error("大纲内容为空。");
      }
    } catch (error: any) {
      setGlobalError(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleOutlineConfirm = async () => {
    if (!config) return;
    setCurrentStep(AppStep.GENERATION);
    generateAllSlides(slides, config);
  };

  const generateAllSlides = async (currentSlides: SlideContent[], cfg: GenerationConfig) => {
    const updateSlideState = (id: string, updates: Partial<SlideContent>) => {
      setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
    };

    for (const slide of currentSlides) {
      updateSlideState(slide.id, { isGenerating: true, error: undefined });
      try {
        const imageUrl = await generateSlideImage(slide, cfg.style, cfg.userImage);
        updateSlideState(slide.id, { isGenerating: false, generatedImageUrl: imageUrl });
      } catch (e: any) {
        updateSlideState(slide.id, { isGenerating: false, error: "生成失败" });
      }
    }
  };

  const handleUpdateSlide = (id: string, updates: Partial<SlideContent>) => {
    setSlides(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const handleRegenerateSlide = async (id: string) => {
    if (!config) return;
    const slide = slides.find(s => s.id === id);
    if (!slide) return;
    handleUpdateSlide(id, { isGenerating: true, error: undefined });
    try {
      const imageUrl = await generateSlideImage(slide, config.style, config.userImage);
      handleUpdateSlide(id, { isGenerating: false, generatedImageUrl: imageUrl });
    } catch {
      handleUpdateSlide(id, { isGenerating: false, error: "重试失败" });
    }
  };

  if (isCheckingKey) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>;

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-blue-600"><Layers /><span className="font-bold text-lg">Gemini PPT 工作台</span></div>
          <button onClick={handleSelectKey} className="text-xs text-slate-400">切换 Key</button>
        </div>
      </header>
      {globalError && <div className="max-w-4xl mx-auto mt-4 px-6"><div className="bg-red-50 p-4 rounded-xl text-red-800 text-sm">{globalError}</div></div>}
      <main className="p-6">
        {currentStep === AppStep.INPUT && <StepInput onNext={handleConfigSubmit} isLoading={isLoading} />}
        {currentStep === AppStep.OUTLINE && <StepOutline slides={slides} onUpdateSlide={handleUpdateSlide} onNext={handleOutlineConfirm} isLoading={isLoading} />}
        {currentStep === AppStep.GENERATION && <StepGeneration slides={slides} onRegenerate={handleRegenerateSlide} />}
      </main>
    </div>
  );
};
export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { SlideContent, SlideStyle } from '../types';
import { STYLES } from '../constants';

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found. Please select an API Key first.");
  return new GoogleGenAI({ apiKey });
};

export const generateOutline = async (
  text: string,
  count: number,
  style: SlideStyle
): Promise<Omit<SlideContent, 'isGenerating'>[]> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);
  const truncatedText = text.length > 25000 ? text.substring(0, 25000) + "..." : text;

  const prompt = `
    你是一位顶尖的策略咨询顾问。基于提供的“原始素材”，制作一份深度、专业且全面的 PPT 大纲。
    页数：${count}
    风格：${styleDef?.name}。

    技术要求：
    - JSON 数组输出。
    - Title & Bullet Points: 中文。
    - Visual Description: 英文（用于生成背景图的指令）。

    素材：
    ${truncatedText}
  `;

  const schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING },
        bulletPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
        visualPrompt: { type: Type.STRING }
      },
      required: ["title", "bulletPoints", "visualPrompt"],
    }
  };

  const callModel = async (modelName: string, configOverrides: any) => {
    const config = {
      responseMimeType: 'application/json',
      responseSchema: schema,
      systemInstruction: "你是一个专业的PPT架构师。只输出JSON格式内容。",
      ...configOverrides
    };
    const response = await ai.models.generateContent({
      model: modelName,
      contents: [{ parts: [{ text: prompt }] }],
      config
    });
    if (!response.text) throw new Error("Empty response");
    return JSON.parse(response.text.trim());
  };

  try {
    const rawData = await callModel('gemini-3-pro-preview', {
      maxOutputTokens: 16384,
      thinkingConfig: { thinkingBudget: 8192 } 
    });
    return processRawData(rawData);
  } catch (err) {
    try {
      const rawData = await callModel('gemini-3-pro-preview', { maxOutputTokens: 12000 });
      return processRawData(rawData);
    } catch {
      const rawData = await callModel('gemini-3-flash-preview', { maxOutputTokens: 12000 });
      return processRawData(rawData);
    }
  }
};

const processRawData = (rawData: any[]): Omit<SlideContent, 'isGenerating'>[] => {
  return rawData.map((item: any, index: number) => ({
    id: `slide-${Date.now()}-${index}`,
    pageNumber: index + 1,
    title: item.title || `Slide ${index + 1}`,
    bulletPoints: Array.isArray(item.bulletPoints) ? item.bulletPoints : [],
    visualPrompt: item.visualPrompt || "Professional background",
  }));
};

export const generateSlideImage = async (
  slide: SlideContent,
  style: SlideStyle,
  userImageBase64?: string,
  refinement?: string
): Promise<string> => {
  const ai = getClient();
  const styleDef = STYLES.find(s => s.id === style);

  const textPart = {
    text: `
      ${styleDef?.promptModifier}

      TASK: Create a professional slide page.
      TITLE: "${slide.title}"
      BULLET POINTS: ${slide.bulletPoints.join('; ')}
      INITIAL VISUAL CONCEPT: ${slide.visualPrompt}

      ${refinement ? `CRITICAL MODIFICATION REQUEST: "${refinement}". Please strictly follow this new user instruction while maintaining the original content and overall professional style.` : ""}

      ${userImageBase64 ? "USER PORTRAIT INTEGRATION: I have provided a photo. Identify the person and feature them as the professional speaker or central character. Integrate them naturally into the layout." : ""}

      MANDATORY: High-quality professional slide layout, legible Chinese text, aesthetic balance.
    `
  };

  const parts: any[] = [textPart];
  if (userImageBase64) {
    parts.push({
      inlineData: {
        data: userImageBase64.split(',')[1] || userImageBase64,
        mimeType: 'image/jpeg'
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: { aspectRatio: "16:9", imageSize: "1K" }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image data");
  } catch (error) {
    console.error(`Image generation error:`, error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { SlideContent } from '../types';
import { RefreshCw, Download, Loader2, Clock, Hourglass, AlertCircle, Send } from 'lucide-react';
import { jsPDF } from 'jspdf'; 

interface Props {
  slides: SlideContent[];
  onRegenerate: (slideId: string, refinement?: string) => void;
}

const GeneratingPlaceholder = ({ pageNumber, isOverlay = false, customText }: { pageNumber: number, isOverlay?: boolean, customText?: string }) => {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const duration = 12000; 
    const interval = 100;
    const increment = 100 / (duration / interval);
    const timer = setInterval(() => {
      setProgress(prev => {
        if (prev >= 90) return prev + (increment * 0.1); 
        if (prev >= 98) return prev;
        return prev + increment;
      });
    }, interval);
    return () => clearInterval(timer);
  }, []);

  const remainingSeconds = Math.max(0, Math.ceil(12 * (1 - Math.min(progress, 100) / 100)));

  return (
    <div className={`w-full h-full flex flex-col items-center justify-center text-white p-6 relative overflow-hidden ${isOverlay ? 'bg-slate-900/90 backdrop-blur-sm' : 'bg-slate-800'}`}>
      <div className="relative z-10 flex flex-col items-center w-full max-w-xs">
        <Loader2 className="w-12 h-12 text-blue-400 animate-spin mb-5" />
        <h3 className="text-xl font-semibold mb-2 text-white tracking-wide">
          {customText || `正在生成第 ${pageNumber} 页`}
        </h3>
        <p className="text-slate-400 text-sm mb-6 text-center font-light">
          Gemini 正在重绘视觉细节...
        </p>
        <div className="w-full h-2 bg-slate-700/50 rounded-full overflow-hidden mb-4">
          <div className="h-full bg-blue-500 transition-all duration-300 ease-linear" style={{ width: `${Math.min(progress, 100)}%` }} />
        </div>
        <div className="flex items-center gap-2 text-xs text-blue-200/80 font-medium">
          <Clock className="w-3.5 h-3.5" />
          <span>剩余约 {remainingSeconds} 秒</span>
        </div>
      </div>
    </div>
  );
};

const StepGeneration: React.FC<Props> = ({ slides, onRegenerate }) => {
  const [refinements, setRefinements] = useState<Record<string, string>>({});
  const isAllDone = slides.every(s => !s.isGenerating && s.generatedImageUrl);

  const handleRefine = (id: string) => {
    const text = refinements[id];
    if (!text?.trim()) return;
    onRegenerate(id, text);
    setRefinements(prev => ({ ...prev, [id]: '' })); // Clear input
  };

  const handleDownloadPDF = () => {
    const doc = new jsPDF({ orientation: 'landscape', unit: 'px', format: [1920, 1080] });
    let pagesAdded = 0;
    slides.forEach((slide) => {
      if (slide.generatedImageUrl) {
        if (pagesAdded > 0) doc.addPage();
        doc.addImage(slide.generatedImageUrl, 'PNG', 0, 0, 1920, 1080);
        pagesAdded++;
      }
    });
    doc.save('gemini-presentation.pdf');
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20">
      <div className="flex justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200 sticky top-4 z-20">
        <div>
          <h2 className="text-xl font-bold text-slate-800">最终幻灯片生成</h2>
          <p className="text-sm text-slate-500">
            {isAllDone ? "制作完成。如不满意，可在下方输入修改要求重新生成。" : "正在按顺序生成高保真幻灯片..."}
          </p>
        </div>
        <button
          onClick={handleDownloadPDF}
          className="px-6 py-2 rounded-lg font-medium bg-blue-600 hover:bg-blue-700 text-white shadow-lg flex items-center gap-2"
        >
          <Download className="w-4 h-4" /> 下载 PDF
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        {slides.map((slide) => (
          <div key={slide.id} className="space-y-3">
            <div className="group relative rounded-xl overflow-hidden aspect-video shadow-lg bg-white border border-slate-200">
              {(() => {
                if (slide.error && !slide.isGenerating) {
                  return (
                    <div className="w-full h-full flex flex-col items-center justify-center bg-red-50 p-6 text-center">
                      <AlertCircle className="w-8 h-8 text-red-500 mb-2" />
                      <p className="text-red-800 text-sm font-medium">生成失败</p>
                      <button onClick={() => onRegenerate(slide.id)} className="mt-4 bg-red-600 text-white px-4 py-2 rounded-lg text-xs">重试</button>
                    </div>
                  );
                }
                else if (slide.isGenerating) {
                  return <GeneratingPlaceholder pageNumber={slide.pageNumber} isOverlay={!!slide.generatedImageUrl} customText={slide.generatedImageUrl ? "正在应用您的修改要求..." : undefined} />;
                }
                else if (slide.generatedImageUrl) {
                  return (
                    <>
                      <img src={slide.generatedImageUrl} alt={slide.title} className="w-full h-full object-cover" />
                      <div className="absolute top-4 left-4 bg-black/50 backdrop-blur-md text-white text-xs px-2 py-1 rounded border border-white/10 z-10">
                        P{slide.pageNumber}
                      </div>
                    </>
                  );
                }
                else {
                  return <div className="w-full h-full flex items-center justify-center bg-slate-50"><Hourglass className="text-slate-300" /></div>;
                }
              })()}
            </div>

            {/* Refinement Input */}
            {slide.generatedImageUrl && !slide.isGenerating && (
              <div className="flex gap-2 animate-fade-in">
                <div className="relative flex-1">
                  <input
                    type="text"
                    placeholder="输入修改意见 (如: 换成深色背景, 人物放大...)"
                    className="w-full pl-4 pr-10 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm transition-all"
                    value={refinements[slide.id] || ''}
                    onChange={(e) => setRefinements(prev => ({ ...prev, [slide.id]: e.target.value }))}
                    onKeyDown={(e) => e.key === 'Enter' && handleRefine(slide.id)}
                  />
                  <button 
                    onClick={() => handleRefine(slide.id)}
                    className="absolute right-2 top-1.5 p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                  >
                    <Send className="w-4 h-4" />
                  </button>
                </div>
                <button 
                  onClick={() => onRegenerate(slide.id)}
                  className="p-2.5 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-xl transition-colors shadow-sm"
                  title="完全重新生成"
                >
                  <RefreshCw className="w-5 h-5" />
                </button>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

